# nginx configuration update — /etc/nginx/conf.d/patient-portal.conf

server {
    listen 443 ssl;
    server_name patient.chf-example.org;

    # Disable TLS 1.0 and 1.1 — allow only TLS 1.2 and 1.3
    ssl_protocols TLSv1.2 TLSv1.3;

    # Strong cipher suites only
    ssl_ciphers 'ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384:ECDHE-ECDSA-CHACHA20-POLY1305:ECDHE-RSA-CHACHA20-POLY1305:DHE-RSA-AES128-GCM-SHA256';
    ssl_prefer_server_ciphers off;

    # Enable HSTS
    add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

    # ... rest of config
}

# After updating, reload nginx:
# sudo nginx -t && sudo systemctl reload nginx

# Verify with:
# testssl.sh --protocols patient.chf-example.org
